#!/usr/bin/env python3
# apply_new_cards.py — add portraits for the 4 new characters
# (Osric a912, Yorick a913, Reynaldo a914 [hamlet]; Winkie Soldier a915 [oz]).
# New asset indices, raw base64 JPEG. Pairs with the updated game.src.html that adds the cards.
# Usage from repo root:  python3 apply_new_cards.py  &&  python3 build.py
import json, os, sys
root=os.path.dirname(os.path.abspath(__file__)); AJ=os.path.join(root,"assets","assets.json")
NEW={
  "a912": "",
  "a913": "",
  "a914": "",
  "a915": "",
}

if not os.path.exists(AJ): sys.exit("[apply] assets/assets.json not found — run from repo root.")
a=json.load(open(AJ))
def raw_only(v):
    i=v.find('base64,'); return v[i+7:] if i!=-1 else v
ch=[]
for k,v in NEW.items():
    nv=raw_only(v)
    if a.get(k)!=nv: a[k]=nv; ch.append(k)
json.dump(a,open(AJ,"w"))
print(f"[apply] new-card portraits -> added {sorted(ch) or '(none)'}")
print("[apply] done. Next: python3 build.py")
